  ('dietitian-moex-00463', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '甘油生合成途徑（glyceroneogenesis）與細胞能量消耗需求有關，因此受到嚴密調節，下列敘述何者錯 誤？', '["糖皮質激素可影響肝臟甘油生合成的速率", "脂肪組織的甘油生合成途徑受抑制時，會增加血液游離脂肪酸之濃度", "肝臟與脂肪細胞會一致且同步進行甘油生合成途徑", "甘油可藉由二羥基丙酮磷酸（dihydroxyacetone phosphate）轉換成甘油-3-磷酸（glycerol-3- phosphate）參與三酸甘油酯之合成"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
